  "$id": "https://xananode.org/schemas/nanopublication.schema.json",
  "title": "XanaNode Nanopublication Profile",
  "type": "object",
  "additionalProperties": false,
  "required": ["id", "claim", "assertion", "provenance", "publication_info"],
  "properties": {
    "id": { "type": "string" },
    "claim": { "type": "string" },
    "assertion": {
      "type": "object",
      "additionalProperties": false,
      "required": ["summary"],
      "properties": {
        "summary": { "type": "string" },
        "relationships": {
          "type": "array",
          "items": { "type": "string" }
        }
      }
    },
    "provenance": {
      "type": "object",
      "additionalProperties": false,
      "properties": {
        "asserted_by": { "type": "string" },
        "asserted_at": { "type": "string", "format": "date-time" },
        "evidence": {
          "type": "array",
          "items": { "type": "string" }
        }
      }
    },
    "publication_info": {
      "type": "object",
      "additionalProperties": false,
      "properties": {
        "published_by": { "type": "string" },
        "published_at": { "type": "string", "format": "date-time" },
        "license": { "type": "string" },
        "content_id": { "type": "string" }
      }
    }
  }
}

{
  "$schema": "https://json-schema.org/draft/2020-12/schema",
  "$id": "https://xananode.org/schemas/property-registry.schema.json",
  "title": "XanaNode Property Registry",
  "type": "object",
  "additionalProperties": false,
  "required": ["id", "version", "property_registry"],
  "properties": {
    "$schema": { "type": "string" },
    "id": {
      "type": "string",
      "pattern": "^[a-z][a-z0-9_-]*(\\.[a-z][a-z0-9_-]*)*:[a-z][a-z0-9_-]*$"
    },
    "version": { "type": "string" },
    "description": { "type": "string" },
    "property_registry": {
      "type": "array",
      "items": {
        "type": "object",
        "additionalProperties": false,
        "required": ["id", "label", "category", "value_schema"],
        "properties": {
          "id": {
            "type": "string",
            "pattern": "^([a-z][a-z0-9_-]*(\\.[a-z][a-z0-9_-]*)*:)?[a-z][a-z0-9_-]*$"
          },
          "label": { "type": "string" },
          "description": { "type": "string" },
          "category": {
            "type": "string",
            "enum": [
              "identity",
              "time",
              "space",
              "quantity",
              "money",
              "classification",
              "reference",
              "epistemology",
              "workflow",
              "attention",
              "communication"
            ]
          },
          "aliases": {
            "type": "array",
            "items": { "type": "string" },
            "uniqueItems": true
          },
          "applies_to": {
            "type": "array",
            "items": { "type": "string" },
            "uniqueItems": true
          },
          "canonical_unit": { "type": "string" },
          "unit_system": {
            "type": "string",
            "enum": ["SI", "ISO-4217", "ISO-8601", "WGS84", "none"]
          },
          "value_schema": {
            "type": "object",
            "description": "JSON Schema fragment for validating this property value."
          },
          "examples": {
            "type": "array",
            "items": true
          }
        }
      }
    }
  }
}

{
  "$schema": "https://json-schema.org/draft/2020-12/schema",
  "$id": "https://xananode.org/schemas/ro-crate-metadata.schema.json",
  "title": "XanaNode RO-Crate Companion Metadata",
  "type": "object",
  "additionalProperties": true,
  "required": ["@context", "@graph"],
  "properties": {
    "@context": {},
    "@graph": {
      "type": "array",
      "items": { "type": "object" }
    }
  }
}

{
  "$schema": "https://json-schema.org/draft/2020-12/schema",
  "$id": "https://xananode.org/schemas/substrate-diff.schema.json",
  "title": "Substrate Diff",
  "type": "object",
  "additionalProperties": false,
  "required": ["id", "base", "head", "changes"],
  "properties": {
    "id": { "type": "string" },
    "base": { "type": "string" },
    "head": { "type": "string" },
    "generated_at": { "type": "string", "format": "date-time" },
    "changes": {
      "type": "object",
      "additionalProperties": false,
      "required": ["nodes", "relationships", "schemas", "fragments"],
      "properties": {
        "nodes": { "$ref": "#/$defs/changeSet" },
        "relationships": { "$ref": "#/$defs/changeSet" },
        "schemas": { "$ref": "#/$defs/changeSet" },
        "fragments": { "$ref": "#/$defs/changeSet" }
      }
    },
    "conflicts": {
      "type": "array",
      "items": {
        "type": "object",
        "additionalProperties": false,
        "required": ["type", "summary"],
        "properties": {
          "type": { "type": "string" },
          "nodes": {
            "type": "array",
            "items": { "type": "string" }
          },
          "resolution": { "type": "string" },
          "summary": { "type": "string" }
        }
      }
    }
  },
  "$defs": {
    "changeSet": {
      "type": "object",
      "additionalProperties": false,
      "required": ["added", "removed", "changed"],
      "properties": {
        "added": {
          "type": "array",
          "items": { "type": "string" }
        },
        "removed": {
          "type": "array",
          "items": { "type": "string" }
        },
        "changed": {
          "type": "array",
          "items": { "type": "string" }
        }
      }
    }
  }
}

{
  "$schema": "https://json-schema.org/draft/2020-12/schema",
  "$id": "https://xananode.org/schemas/substrate-layout.schema.json",
  "title": "XanaNode Substrate Layout Registry",
  "type": "object",
  "additionalProperties": false,
  "required": ["id", "version", "description", "required_paths", "recognized_paths"],
  "properties": {
    "$schema": { "type": "string" },
    "id": { "type": "string" },
    "version": { "type": "string" },
    "description": { "type": "string" },
    "root_contract": { "type": "string" },
    "required_paths": {
      "type": "array",
      "items": { "$ref": "#/$defs/path_record" }
    },
    "recognized_paths": {
      "type": "array",
      "items": { "$ref": "#/$defs/path_record" }
    },
    "authoring_paths": {
      "type": "array",
      "items": { "$ref": "#/$defs/path_record" }
    },
    "archive_rules": {
      "type": "array",
      "items": { "type": "string" }
    }
  },
  "$defs": {
    "path_record": {
      "type": "object",
      "additionalProperties": false,
      "required": ["path", "role"],
      "properties": {
        "path": { "type": "string" },
        "role": { "type": "string" },
        "required": { "type": "boolean" },
        "kind": {
          "type": "string",
          "enum": ["file", "directory", "glob"]
        },
        "format": { "type": "string" },
        "description": { "type": "string" },
        "tools_must_preserve": { "type": "boolean" }
      }
    }
  }
}

{
  "$schema": "https://json-schema.org/draft/2020-12/schema",
  "$id": "https://xananode.org/schemas/substrate-manifest.schema.json",
  "title": "Substrate Manifest",
  "type": "object",
  "additionalProperties": false,
  "required": ["id", "name", "version", "namespace", "repository"],
  "properties": {
    "id": { "type": "string" },
    "name": { "type": "string" },
    "version": { "type": "string" },
    "namespace": { "type": "string" },
    "repository": {
      "type": "object",
      "additionalProperties": false,
      "required": ["type", "url", "default_branch"],
      "properties": {
        "type": {
          "type": "string",
          "enum": ["git"]
        },
        "url": { "type": "string" },
        "default_branch": { "type": "string" },
        "path": { "type": "string" },
        "commit": { "type": "string" }
      }
    },
    "federation": {
      "type": "object",
      "additionalProperties": false,
      "properties": {
        "inbox": { "type": "string", "format": "uri" },
        "outbox": { "type": "string", "format": "uri" },
        "feed": { "type": "string", "format": "uri" },
        "merge_reports": { "type": "string", "format": "uri" },
        "mapping_endpoint": { "type": "string", "format": "uri" }
      }
    },
    "trust": {
      "type": "object",
      "additionalProperties": false,
      "properties": {
        "signed": { "type": "boolean" },
        "signature": { "type": "string" },
        "public_key": { "type": "string" },
        "trust_scope": {
          "type": "array",
          "items": {
            "type": "string",
            "enum": ["local_substrate", "imported_schema", "mapping", "assertion"]
          }
        }
      }
    },
    "description": { "type": "string" },
    "branding": {
      "$ref": "#/$defs/branding"
    },
    "build_metadata": {
      "$ref": "#/$defs/build_metadata"
    },
    "schema_version": { "type": "string" },
    "license": { "type": "string" },
    "sharing": {
      "type": "object",
      "description": "Substrate-level sharing policy. The default is shareable unless a node, trail, or explicit rule excludes records.",
      "additionalProperties": false,
      "properties": {
        "default_shareable": {
          "type": "boolean",
          "description": "Whether nodes are shareable by default when they do not declare their own sharing rule."
        },
        "excluded_nodes": {
          "type": "array",
          "description": "Node ids that must not be included in shared exports or mounted public projections.",
          "items": { "type": "string" },
          "uniqueItems": true
        },
        "excluded_trails": {
          "type": "array",
          "description": "Trail node ids whose listed trail nodes should be excluded unless a node explicitly opts back in.",
          "items": { "type": "string" },
          "uniqueItems": true
        },
        "excluded_relationships": {
          "type": "array",
          "description": "Relationship ids that must not be included in shared exports or mounted public projections.",
          "items": { "type": "string" },
          "uniqueItems": true
        },
        "rules": {
          "type": "array",
          "description": "Named sharing rules for selectors a tool understands, such as type, subtype, tag, path, trail, or namespace.",
          "items": {
            "type": "object",
            "additionalProperties": false,
            "required": ["selector", "shareable"],
            "properties": {
              "selector": {
                "type": "object",
                "additionalProperties": true,
                "description": "Selector interpreted by tools, commonly {type}, {subtype}, {tag}, {trail}, {path}, or {namespace}."
              },
              "shareable": { "type": "boolean" },
              "scope": {
                "type": "string",
                "enum": ["public", "unlisted", "trusted", "private"]
              },
              "reason": { "type": "string" }
            }
          }
        }
      }
    },
    "maintainers": {
      "type": "array",
      "items": {
        "type": "object",
        "additionalProperties": false,
        "required": ["name"],
        "properties": {
          "name": { "type": "string" },
          "url": { "type": "string", "format": "uri" }
        }
      }
    },
    "imports": {
      "type": "array",
      "items": {
        "oneOf": [
          { "type": "string" },
          {
            "type": "object",
            "additionalProperties": false,
            "required": ["id", "source", "mode"],
            "properties": {
              "id": { "type": "string" },
              "source": { "type": "string" },
              "mode": {
                "type": "string",
                "enum": ["mounted", "imported", "merged", "absorbed"]
              },
              "version": { "type": "string" },
              "description": { "type": "string" },
              "required": { "type": "boolean" },
              "repository": {
                "type": "object",
                "additionalProperties": false,
                "properties": {
                  "type": {
                    "type": "string",
                    "enum": ["git"]
                  },
                  "url": { "type": "string" },
                  "branch": { "type": "string" },
                  "commit": { "type": "string" },
                  "archive": { "type": "string" }
                }
              },
              "archive": {
                "type": "object",
                "additionalProperties": false,
                "properties": {
                  "media_type": { "type": "string" },
                  "file": { "type": "string" },
                  "sha256": { "type": "string" },
                  "created_at": { "type": "string", "format": "date-time" }
                }
              },
              "namespace_mappings": {
                "type": "array",
                "items": {
                  "type": "object",
                  "additionalProperties": false,
                  "required": ["from", "to", "scope"],
                  "properties": {
                    "from": { "type": "string" },
                    "to": { "type": "string" },
                    "scope": {
                      "type": "string",
                      "enum": ["relationships", "all"]
                    },
                    "reason": { "type": "string" }
                  }
                }
              },
              "trust": {
                "type": "object",
                "additionalProperties": false,
                "properties": {
                  "signed": { "type": "boolean" },
                  "signature": { "type": "string" },
                  "public_key": { "type": "string" }
                }
              }
            }
          }
        ]
      }
    },
    "pack": {
      "type": "object",
      "description": "Metadata used when this manifest describes a portable substrate pack rather than only a live authored substrate.",
      "additionalProperties": false,
      "properties": {
        "mode": {
          "type": "string",
          "enum": ["mounted", "imported", "merged", "absorbed"]
        },
        "built_by": { "type": "string" },
        "built_at": { "type": "string", "format": "date-time" },
        "build_metadata": {
          "$ref": "#/$defs/build_metadata"
        },
        "portable": { "type": "boolean" },
        "archive_name": { "type": "string" },
        "archive_media_type": { "type": "string" },
        "source_manifests": {
          "type": "array",
          "items": {
            "type": "object",
            "additionalProperties": true,
            "properties": {
              "id": { "type": "string" },
              "name": { "type": "string" },
              "namespace": { "type": "string" },
              "version": { "type": "string" },
              "repository": { "type": "object" }
            }
          }
        }
      }
    },
    "extensions": {
      "type": "array",
      "items": { "type": "string" }
    }
  },
  "$defs": {
    "branding": {
      "type": "object",
      "description": "Portable branding metadata for a substrate or pack. Branding assets should be represented as media nodes and referenced here by node id.",
      "additionalProperties": false,
      "properties": {
        "brand_name": { "type": "string" },
        "tagline": { "type": "string" },
        "description": { "type": "string" },
        "primary_media": { "type": "string" },
        "logo_media": { "type": "string" },
        "icon_media": { "type": "string" },
        "primary_color": {
          "type": "string",
          "pattern": "^#[0-9A-Fa-f]{6}$"
        },
        "accent_color": {
          "type": "string",
          "pattern": "^#[0-9A-Fa-f]{6}$"
        },
        "background_color": {
          "type": "string",
          "pattern": "^#[0-9A-Fa-f]{6}$"
        },
        "text_color": {
          "type": "string",
          "pattern": "^#[0-9A-Fa-f]{6}$"
        },
        "source_node": { "type": "string" },
        "rights_status": { "type": "string" },
        "license": { "type": "string" },
        "updated_at": { "type": "string", "format": "date-time" },
        "reason": { "type": "string" }
      }
    },
    "build_metadata": {
      "type": "object",
      "description": "Build and runtime provenance for generated substrates, packs, renderer output, and software-created artifacts.",
      "additionalProperties": false,
      "properties": {
        "version": { "type": "string" },
        "git_commit": { "type": "string" },
        "git_branch": { "type": "string" },
        "repository": { "type": "string" },
        "built_at": { "type": "string", "format": "date-time" },
        "compiled_at": { "type": "string", "format": "date-time" },
        "generated_at": { "type": "string", "format": "date-time" },
        "built_by": { "type": "string" },
        "runtime": { "type": "string" },
        "platform": { "type": "string" },
        "dependencies": {
          "type": "array",
          "items": {
            "type": "object",
            "additionalProperties": false,
            "required": ["name"],
            "properties": {
              "name": { "type": "string" },
              "version": { "type": "string" },
              "repository": { "type": "string" },
              "relationship": { "type": "string" }
            }
          }
        }
      }
    }
  }
}

{
  "$schema": "https://json-schema.org/draft/2020-12/schema",
  "$id": "https://xananode.org/schemas/substrate-node.schema.json",
  "title": "Substrate Node",
  "type": "object",
  "additionalProperties": true,
  "required": ["id", "title", "type", "importance", "summary", "relationships"],
  "properties": {
    "id": {
      "type": "string",
      "pattern": "^[a-z][a-z0-9_-]*(\\.[a-z][a-z0-9_-]*)*:[a-z][a-z0-9_-]*/[^\\s#]+$"
    },
    "title": { "type": "string" },
    "type": {
      "type": "string",
      "pattern": "^([a-z][a-z0-9_-]*(\\.[a-z][a-z0-9_-]*)*:)?[a-z][a-z0-9_-]*$"
    },
    "subtype": {
      "type": "string",
      "description": "A narrower kind within the primary node type, such as git_repository, official_site, documentation, support_page, screenshot, logo, or web_snapshot.",
      "pattern": "^([a-z][a-z0-9_-]*(\\.[a-z][a-z0-9_-]*)*:)?[a-z][a-z0-9_-]*$"
    },
    "subtypes": {
      "type": "array",
      "description": "Additional narrower kinds within the primary node type. Use when one node needs more than one subtype without changing its primary type.",
      "items": {
        "type": "string",
        "pattern": "^([a-z][a-z0-9_-]*(\\.[a-z][a-z0-9_-]*)*:)?[a-z][a-z0-9_-]*$"
      },
      "uniqueItems": true
    },
    "facets": {
      "type": "array",
      "description": "Secondary node roles used when one knowledge object participates in multiple modeling categories without duplicating its identity.",
      "items": {
        "type": "string",
        "pattern": "^([a-z][a-z0-9_-]*(\\.[a-z][a-z0-9_-]*)*:)?[a-z][a-z0-9_-]*$"
      },
      "uniqueItems": true
    },
    "status": { "type": "string" },
    "importance": {
      "type": "integer",
      "minimum": 1,
      "maximum": 5
    },
    "summary": { "type": "string" },
    "created_by": { "type": "string" },
    "created_at": { "type": "string", "format": "date-time" },
    "updated_at": { "type": "string", "format": "date-time" },
    "source_url": { "type": "string", "format": "uri" },
    "rights_status": { "type": "string" },
    "sharing": {
      "type": "object",
      "description": "Node-level sharing policy. Nodes are shareable by default unless this object or a substrate-level rule says otherwise.",
      "additionalProperties": false,
      "properties": {
        "shareable": {
          "type": "boolean",
          "description": "Whether this node may be included in exported, published, federated, or shared packs. Defaults to true."
        },
        "scope": {
          "type": "string",
          "description": "The intended sharing scope for tools that support private workspaces or limited review.",
          "enum": ["public", "unlisted", "trusted", "private"]
        },
        "reason": { "type": "string" },
        "review_status": {
          "type": "string",
          "enum": ["allowed", "blocked", "needs_review"]
        }
      }
    },
    "asset_path": {
      "type": "string",
      "description": "Portable relative path to a local asset file inside the substrate or pack, usually used by media nodes."
    },
    "asset_role": {
      "type": "string",
      "description": "The role this asset plays for the node, such as primary_media, source_snapshot, thumbnail, transcript, attachment, or archival_copy."
    },
    "media_type": { "type": "string" },
    "mime_type": { "type": "string" },
    "alt": { "type": "string" },
    "caption": { "type": "string" },
    "source_snapshot": {
      "type": "object",
      "description": "Metadata for a captured representation of an external source page.",
      "additionalProperties": false,
      "properties": {
        "captured_at": { "type": "string", "format": "date-time" },
        "source_url": { "type": "string", "format": "uri" },
        "method": {
          "type": "string",
          "enum": ["opengraph", "screenshot", "readability", "manual", "archive"]
        },
        "content_id": { "type": "string" },
        "rights_status": { "type": "string" },
        "tool": { "type": "string" }
      }
    },
    "confidence": { "type": "string" },
    "uncertainty_level": {
      "type": "string",
      "description": "A canonical epistemic uncertainty level for questions, hypotheses, claims, knowledge gaps, responses, or first-class relationships.",
      "enum": ["unknown", "low", "medium", "high", "unresolved"]
    },
    "review_status": {
      "type": "string",
      "description": "Workflow review state for a node or relationship being authored, validated, merged, or deprecated.",
      "enum": ["draft", "needs_review", "under_review", "approved", "rejected", "deprecated"]
    },
    "research_priority": {
      "type": "integer",
      "description": "Priority signal for inquiry, problems, and knowledge gaps.",
      "minimum": 1,
      "maximum": 5
    },
    "evidence_strength": {
      "type": "string",
      "description": "Compact assessment of the evidence available for a claim, hypothesis, response, or relationship.",
      "enum": ["none", "weak", "moderate", "strong", "decisive", "contested"]
    },
    "communication_model": {
      "type": "string",
      "description": "Participant topology for a first-class communication.",
      "enum": ["one_to_one", "one_to_many", "many_to_one", "many_to_many"]
    },
    "communication_pattern": {
      "type": "string",
      "description": "Semantic communication pattern beyond participant count.",
      "enum": [
        "dialogue",
        "broadcast",
        "collection",
        "coordination",
        "negotiation",
        "debate",
        "consensus",
        "instruction",
        "query_response",
        "publication"
      ]
    },
    "protocol_id": { "type": "string" },
    "content_id": { "type": "string" },
    "version_id": { "type": "string" },
    "software_version": {
      "type": "string",
      "description": "Semantic or package version of a software project, component, renderer, SDK, or application."
    },
    "build_metadata": {
      "type": "object",
      "description": "Build and runtime provenance for software nodes, generated packs, and projection artifacts.",
      "additionalProperties": false,
      "properties": {
        "version": { "type": "string" },
        "git_commit": { "type": "string" },
        "git_branch": { "type": "string" },
        "repository": { "type": "string" },
        "built_at": { "type": "string", "format": "date-time" },
        "compiled_at": { "type": "string", "format": "date-time" },
        "generated_at": { "type": "string", "format": "date-time" },
        "built_by": { "type": "string" },
        "runtime": { "type": "string" },
        "platform": { "type": "string" },
        "dependencies": {
          "type": "array",
          "items": {
            "type": "object",
            "additionalProperties": false,
            "required": ["name"],
            "properties": {
              "name": { "type": "string" },
              "version": { "type": "string" },
              "repository": { "type": "string" },
              "relationship": { "type": "string" }
            }
          }
        }
      }
    },
    "source_content_id": { "type": "string" },
    "source_version_id": { "type": "string" },
    "signature": { "type": "string" },
    "source_node": { "type": "string" },
    "fragment_id": {
      "type": "string",
      "pattern": "^[A-Za-z0-9._-]+$"
    },
    "tumbler": {
      "type": "string",
      "pattern": "^[a-z][a-z0-9_-]*(\\.[a-z][a-z0-9_-]*)*:[a-z][a-z0-9_-]*/[^\\s#@]+(@[^\\s#]+)?(#fragment/[A-Za-z0-9._-]+(@[^\\s#]+)?)?$"
    },
    "selector": {
      "type": "object",
      "additionalProperties": true,
      "properties": {
        "type": {
          "type": "string",
          "enum": [
            "semantic-anchor",
            "TextQuoteSelector",
            "TextPositionSelector",
            "FragmentSelector",
            "CssSelector",
            "XPathSelector",
            "RangeSelector"
          ]
        },
        "value": { "type": "string" },
        "exact": { "type": "string" },
        "prefix": { "type": "string" },
        "suffix": { "type": "string" },
        "start": { "type": "integer" },
        "end": { "type": "integer" }
      }
    },
    "relationships": {
      "type": "array",
      "items": {
        "type": "object",
        "additionalProperties": false,
        "required": ["id", "type", "direction"],
        "properties": {
          "id": { "type": "string" },
          "type": {
            "type": "string",
            "pattern": "^([a-z][a-z0-9_-]*(\\.[a-z][a-z0-9_-]*)*:)?[a-z][a-z0-9_-]*$"
          },
          "source": { "type": "string" },
          "target": { "type": "string" },
          "direction": {
            "type": "string",
            "enum": ["incoming", "outgoing"]
          },
          "external": { "type": "boolean" },
          "target_substrate": { "type": "string" }
        }
      }
    }
  },
  "allOf": [
    {
      "if": {
        "properties": {
          "type": { "const": "fragment" }
        },
        "required": ["type"]
      },
      "then": {
        "required": [
          "source_node",
          "source_version_id",
          "source_content_id",
          "fragment_id",
          "tumbler",
          "selector",
          "content_id",
          "version_id"
        ]
      }
    }
  ]
}

